public class Narrowing {
    public static void main(String[] args) {
        int i = 300;
        byte b = (byte) i;    // narrowing
        short s = (short) i;
        System.out.println(b);
        System.out.println(s);
        double d = i;         // widening
        System.out.println(d);
    }
}
